769: // serviceAccountTokenControllerStarter is special because it must run first to set up permissions for other controllers.
770: // It cannot use the "normal" client builder, so it tracks its own.
771: func newServiceAccountTokenControllerDescriptor(rootClientBuilder clientbuilder.ControllerClientBuilder) *ControllerDescriptor {
772: 	return &ControllerDescriptor{
773: 		name:    names.ServiceAccountTokenController,
774: 		aliases: []string{"serviceaccount-token"},
775: 		initFunc: func(ctx context.Context, controllerContext ControllerContext, controllerName string) (controller.Interface, bool, error) {
776: 			return startServiceAccountTokenController(ctx, controllerContext, controllerName, rootClientBuilder)
777: 		},
778: 		// will make sure it runs first before other controllers
779: 		requiresSpecialHandling: true,
780: 	}
